def correct_bracketing(brackets: str):
    if len(brackets) % 2 != 0:
        return False

    stack = []
    for bracket in brackets:
        if bracket == '(':
            stack.append(bracket)
        elif bracket == ')':
            if not stack:
                return False
            stack.pop()

    return len(stack) == 0

