def modp(n: int, p: int):
    result = 1
    if n == 0:
        return result

    base = 2
    exponent = n
    modulus = p

    while exponent > 0:
        if exponent % 2 == 1:
            result = (result * base) % modulus
        base = (base * base) % modulus
        exponent //= 2

    return result

