def closest_integer(value):
    num = float(value)
    floor_val = int(num)
    ceil_val = int(num) + 1

    diff_to_floor = abs(num - floor_val)
    diff_to_ceil = abs(num - ceil_val)

    if diff_to_ceil < diff_to_floor:
        return ceil_val
    elif diff_to_floor < diff_to_ceil:
        return floor_val
    else:
        return ceil_val if num >= 0 else floor_val

