import math

def prime_length(string):

    def is_prime(n):
        if n < 2:
            return False
        for i in range(2, int(math.sqrt(n)) + 1):
            if n % i == 0:
                return False
        return True

    length = len(string)

    if length < 2:
        return False

    return is_prime(length)

