def get_row(lst, x):
    coordinates = []
    for i, row in enumerate(lst):
        for j in range(len(row)-1, -1, -1):
            if row[j] == x:
                coordinates.append((i, j))
    return sorted(coordinates, key=lambda coord: (coord[0], -coord[1]))

