def bf(planet1, planet2):
    planets = {
        "Mercury": 1,
        "Venus": 2,
        "Earth": 3,
        "Mars": 4,
        "Jupiter": 5,
        "Saturn": 6,
        "Uranus": 7,
        "Neptune": 8
    }

    if planet1 not in planets or planet2 not in planets:
        return ()

    start = min(planets[planet1], planets[planet2])
    end = max(planets[planet1], planets[planet2])

    result = [planet for planet, order in planets.items() if start < order < end]
    result.sort(key=lambda x: planets[x])

    return tuple(result)

