def find_max(words):
    unique_char_count = {}

    for word in words:
        unique_chars = set()
        for char in word:
            unique_chars.add(char)
        unique_char_count[word] = len(unique_chars)

    max_count = max(unique_char_count.values())
    max_words = [word for word, count in unique_char_count.items() if count == max_count]

    return min(max_words) if max_words else ""

