def sorted_list_sum(lst):
    if not lst:
        return []

    even_length_words = [word for word in lst if len(word) % 2 == 0]

    if not even_length_words:
        return []

    sorted_words = sorted(even_length_words, key=lambda x: (len(x), x))

    return sorted_words

