def fix_spaces(text):
    result = ""
    prev_char = ""
    consecutive_spaces = 0

    for char in text:
        if char == " ":
            if prev_char == " ":
                consecutive_spaces += 1
            else:
                if consecutive_spaces > 1:
                    result = result[:-consecutive_spaces] + "-" + char
                else:
                    result += "_"
                consecutive_spaces = 1
        else:
            if consecutive_spaces > 1:
                result = result[:-consecutive_spaces] + "-"
            result += char
            consecutive_spaces = 0
        prev_char = char

    if consecutive_spaces > 1:
        result = result[:-consecutive_spaces] + "-"

    if result.startswith(" "):
        result = "_" + result.lstrip()
    if result.endswith(" "):
        result = result.rstrip() + "_"

    return result.replace("  ", "-").replace(" ", "_")

